import React, { useState } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Grid,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  IconButton,
  Card,
  CardContent,
  Divider,
  Alert,
  CircularProgress,
} from '@mui/material';
import {
  Search,
  Person,
  AccountBalance,
  Print,
  Download,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { accountService } from '../../services/accountService';
import { customerService } from '../../services/customerService';
import CustomerSearch from '../customers/CustomerSearch';

const LedgerView = () => {
  const [customer, setCustomer] = useState(null);
  const [ledger, setLedger] = useState([]);
  const [loading, setLoading] = useState(false);
  const [customerSearchOpen, setCustomerSearchOpen] = useState(false);
  const [error, setError] = useState('');

  const handleCustomerSelect = async (selectedCustomer) => {
    setCustomer(selectedCustomer);
    await fetchLedger(selectedCustomer.id);
  };

  const fetchLedger = async (customerId) => {
    setLoading(true);
    try {
      const data = await accountService.getCustomerLedger(customerId);
      setLedger(data);
      setError('');
    } catch (error) {
      setError('Failed to fetch ledger details');
      toast.error('Failed to fetch ledger');
    } finally {
      setLoading(false);
    }
  };

  const getTransactionTypeColor = (type) => {
    const colors = {
      'Invoice': 'primary',
      'Receipt': 'success',
      'Payment': 'warning',
      'Credit Note': 'error',
      'Cash Sale': 'info',
      'Credit Sale': 'primary',
    };
    return colors[type] || 'default';
  };

  const getTransactionType = (entry) => {
    // Determine transaction type based on entry data
    if (entry.type === 'Invoice' && entry.paymentMode === 'CASH') {
      return 'Cash Sale';
    } else if (entry.type === 'Invoice' && entry.paymentMode === 'CREDIT') {
      return 'Credit Sale';
    } else if (entry.type === 'Receipt') {
      return 'Receipt';
    } else if (entry.type === 'Payment') {
      return 'Payment';
    } else if (entry.type === 'Credit Note') {
      return 'Credit Note';
    }
    return entry.type || 'Transaction';
  };

  const calculateTotals = () => {
    let totalDebit = 0;
    let totalCredit = 0;
    let runningBalance = 0;

    // Calculate running balance correctly
    const updatedLedger = ledger.map((entry) => {
      const amount = entry.amount || 0;
      const payment = entry.payment || 0;
      
      // For invoices (debit - customer owes us)
      if (entry.type === 'Invoice') {
        runningBalance += amount;
        totalDebit += amount;
      } 
      // For receipts (credit - customer paid us)
      else if (entry.type === 'Receipt') {
        runningBalance -= payment;
        totalCredit += payment;
      }
      // For payments (debit - we paid customer? usually not in customer ledger)
      else if (entry.type === 'Payment') {
        runningBalance += payment;
        totalDebit += payment;
      }
      // For Credit Notes (credit - we owe customer)
      else if (entry.type === 'Credit Note') {
        runningBalance -= amount;
        totalCredit += amount;
      }
      
      return {
        ...entry,
        balance: runningBalance
      };
    });

    return { 
      totalDebit, 
      totalCredit, 
      balance: runningBalance,
      updatedLedger 
    };
  };

  const totals = calculateTotals();
  const displayLedger = totals.updatedLedger || ledger;

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <AccountBalance sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Customer Ledger
          </Typography>
          <Typography variant="body2" color="textSecondary">
            View customer transaction history
          </Typography>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      <Grid container spacing={3}>
        <Grid item xs={12}>
          <Paper sx={{ p: 3, borderRadius: 2 }}>
            <Box display="flex" gap={2} mb={3} alignItems="center" flexWrap="wrap">
              <TextField
                label="Customer"
                value={customer?.name || ''}
                placeholder="Search customer..."
                sx={{ flexGrow: 1, minWidth: 200 }}
                InputProps={{
                  readOnly: true,
                  endAdornment: (
                    <IconButton onClick={() => setCustomerSearchOpen(true)}>
                      <Search />
                    </IconButton>
                  ),
                }}
              />
              {customer && (
                <Button
                  variant="outlined"
                  color="error"
                  onClick={() => {
                    setCustomer(null);
                    setLedger([]);
                  }}
                >
                  Clear
                </Button>
              )}
              {ledger.length > 0 && (
                <>
                  <Button
                    variant="outlined"
                    startIcon={<Print />}
                    onClick={() => window.print()}
                  >
                    Print
                  </Button>
                  <Button
                    variant="outlined"
                    startIcon={<Download />}
                  >
                    Export
                  </Button>
                </>
              )}
            </Box>

            {customer && (
              <Box mb={3}>
                <Grid container spacing={2}>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Customer Name
                        </Typography>
                        <Typography variant="h6">{customer.name}</Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Phone
                        </Typography>
                        <Typography variant="h6">{customer.phone}</Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Current Balance
                        </Typography>
                        <Typography variant="h6" color={totals.balance > 0 ? 'error' : 'success'}>
                          ₹{Math.abs(totals.balance).toFixed(2)}
                          {totals.balance > 0 ? ' (Receivable)' : totals.balance < 0 ? ' (Payable)' : ''}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                </Grid>

                <Grid container spacing={2} mt={1}>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Total Debit (Sales)
                        </Typography>
                        <Typography variant="h6" color="error">
                          ₹{totals.totalDebit.toFixed(2)}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Total Credit (Payments)
                        </Typography>
                        <Typography variant="h6" color="success">
                          ₹{totals.totalCredit.toFixed(2)}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Net Balance
                        </Typography>
                        <Typography variant="h6" color={totals.balance > 0 ? 'error' : 'success'}>
                          ₹{Math.abs(totals.balance).toFixed(2)}
                          {totals.balance > 0 ? ' (Debit)' : totals.balance < 0 ? ' (Credit)' : ''}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                </Grid>
              </Box>
            )}

            {loading ? (
              <Box display="flex" justifyContent="center" py={4}>
                <CircularProgress />
              </Box>
            ) : displayLedger.length > 0 ? (
              <TableContainer>
                <Table>
                  <TableHead>
                    <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                      <TableCell>Date</TableCell>
                      <TableCell>Type</TableCell>
                      <TableCell>Invoice No</TableCell>
                      <TableCell>Description</TableCell>
                      <TableCell align="right">Debit (Sales)</TableCell>
                      <TableCell align="right">Credit (Payment)</TableCell>
                      <TableCell align="right">Balance</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {displayLedger.map((entry, index) => {
                      const isDebit = entry.type === 'Invoice' || entry.type === 'Payment';
                      const isCredit = entry.type === 'Receipt' || entry.type === 'Credit Note';
                      const amount = entry.amount || 0;
                      const payment = entry.payment || 0;
                      const transactionType = getTransactionType(entry);
                      
                      return (
                        <TableRow key={index}>
                          <TableCell>
                            {entry.date ? new Date(entry.date).toLocaleDateString() : '-'}
                          </TableCell>
                          <TableCell>
                            <Chip
                              label={transactionType}
                              color={getTransactionTypeColor(transactionType)}
                              size="small"
                            />
                          </TableCell>
                          <TableCell>{entry.invoiceNo || '-'}</TableCell>
                          <TableCell>
                            {entry.description || entry.remarks || '-'}
                          </TableCell>
                          <TableCell align="right">
                            {isDebit && amount > 0 ? `₹${amount.toFixed(2)}` : '-'}
                          </TableCell>
                          <TableCell align="right">
                            {isCredit && payment > 0 ? `₹${payment.toFixed(2)}` : '-'}
                          </TableCell>
                          <TableCell align="right">
                            <Typography
                              fontWeight={500}
                              color={entry.balance > 0 ? 'error' : entry.balance < 0 ? 'success' : 'textSecondary'}
                            >
                              ₹{Math.abs(entry.balance).toFixed(2)}
                              {entry.balance > 0 ? ' Dr' : entry.balance < 0 ? ' Cr' : ''}
                            </Typography>
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              </TableContainer>
            ) : customer ? (
              <Box textAlign="center" py={4}>
                <Typography color="textSecondary">
                  No transactions found for this customer
                </Typography>
              </Box>
            ) : (
              <Box textAlign="center" py={4}>
                <Typography color="textSecondary">
                  Search and select a customer to view ledger
                </Typography>
              </Box>
            )}
          </Paper>
        </Grid>
      </Grid>

      <CustomerSearch
        open={customerSearchOpen}
        onClose={() => setCustomerSearchOpen(false)}
        onSelect={handleCustomerSelect}
      />
    </Box>
  );
};

export default LedgerView;
